class LoadAndApplyDataCommand(BaseCommand):
    """Generated command for LoadAndApplyData intent (Composite Transaction)."""
    def __init__(self, node: SceneNode, col_x: Any, col_y: Any, df: Any, path: Any, event_aggregator: EventAggregator):
        super().__init__("LoadAndApplyData", event_aggregator)
        self.sub_commands: List[BaseCommand] = [
            UpdateDataPathCommand(node, path, event_aggregator),
            UpdateDataframeCommand(node, df, event_aggregator),
            SetArtistDataMappingCommand(node, 0, 'x', col_x, event_aggregator),
            SetArtistDataMappingCommand(node, 0, 'y', col_y, event_aggregator)
        ]

    def execute(self):
        self.logger.debug(f"Executing Composite Transaction: LoadAndApplyData")
        for cmd in self.sub_commands:
            cmd.execute()
        self._event_aggregator.publish(Events.NODE_DATA_LOADED)

    def undo(self):
        self.logger.debug(f"Undoing Composite Transaction: LoadAndApplyData")
        for cmd in reversed(self.sub_commands):
            cmd.undo()
        self._event_aggregator.publish(Events.NODE_DATA_LOADED)


