class BatchAlignPlotsCommand(BaseCommand):
    """Generated command for BatchAlignPlots intent (Batch Atom)."""
    def __init__(self, model: ApplicationModel, values: Dict[str, Any], event_aggregator: EventAggregator):
        super().__init__("BatchAlignPlots", event_aggregator)
        self.model = model
        self.new_values = values
        self.path = "plot_properties.geometry"
        self.old_values: Dict[str, Any] = {}

    def execute(self):
        self.logger.debug(f"Executing Batch BatchAlignPlots on path '{self.path}'")
        for node_id, value in self.new_values.items():
            node = self.model.scene_root.find_node_by_id(node_id)
            if node:
                self.old_values[node_id] = self.get_value_by_path(node, self.path)
                self.set_value_by_path(node, self.path, value)
                if self.path.startswith("plot_properties") and hasattr(node, "plot_properties"):
                    node.plot_properties._version += 1
        self._event_aggregator.publish(Events.PLOT_PROPERTY_CHANGED)

    def undo(self):
        self.logger.debug(f"Undoing Batch BatchAlignPlots")
        for node_id, old_value in self.old_values.items():
            node = self.model.scene_root.find_node_by_id(node_id)
            if node:
                self.set_value_by_path(node, self.path, old_value)
                if self.path.startswith("plot_properties") and hasattr(node, "plot_properties"):
                    node.plot_properties._version += 1
        self._event_aggregator.publish(Events.PLOT_PROPERTY_CHANGED)


